import type { FunctionComponent } from 'react';

export type ImageAttributes = {
  alt?: string;
  src?: string;
  src2x?: string;
  title?: string;
};

export type ImageProps = ImageAttributes & {
  className?: string;
  height?: string;
  width?: string;
};

/**
 * A component for rendering images with support for high resolution displays using srcSet.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/image#props | Documentation}
 * @example
 * import { Image } from '@andes/image';
 *
 * const MyComponent = () => (
 *   <div>
 *     <Image
 *      className="custom-class"
 *      src="https://http2.mlstatic.com/path/to/some/image.webp"
 *      title="alt by a11y"
 *     />
 *   </div>
 * );
 */
export const Image: FunctionComponent<ImageProps>;
